features.snippet:
module Bar
  #(parameter int w = 8) (
  input  [w-1:0] a,
  output [w-1:0] b);
  assign b = a;
endmodule

module SubtractWidth
  #(parameter w = 16) (
  input  [w-1:0] data_in,
  output [w-1:0] data_out);
  assign data_out = data_in;
endmodule

module Passthrough
  #(parameter int WIDTH = 8) (
  input  [WIDTH-1:0] in_port,
  output [WIDTH-1:0] out_port);
  assign out_port = in_port;
endmodule
